import React, { useRef, useEffect, useState } from 'react';
import {
  AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemText, Divider, Box, Slider, Input, Button, Modal
} from '@mui/material';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon
} from '@mui/icons-material';

// Shape definitions with their parameters
const shapeDefinitions = {
  select: { text: 'Select Figure...', params: [] },
  point: { text: 'POINT', params: [ {name:'x', label:'X:'}, {name:'y', label:'Y:'} ] },
  line: { text: 'LINE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'} ] },
  circle: { text: 'CIRCLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radius', label:'Radius'} ] },
  rectangle: { text: 'RECTANGLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'width', label:'Width'}, {name:'height', label:'Height'} ] },
  triangle: { text: 'TRIANGLE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'}, {name:'x3', label:'X3:'}, {name:'y3', label:'Y3:'} ] },
  ellipse: { text: 'ELLIPSE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radiusX', label:'Radius X:'}, {name:'radiusY', label:'Radius Y:'} ] },
};

const defaultShape = 'select';

function App() {
  const canvasRef = useRef(null);
  const [figures, setFigures] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#4f46e5');
  const [lineWidth, setLineWidth] = useState(2);
  const [drawerOpen, setDrawerOpen] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [mouseCoords, setMouseCoords] = useState({ x: '--', y: '--' });

  // Draw grid and axes
  const drawGridAndAxes = (ctx, width, height) => {
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, width, height);
    
    // Grid
    ctx.save();
    ctx.strokeStyle = '#e0e0e0';
    ctx.lineWidth = 0.5;
    const gridSpacing = 20;
    for (let x = 0; x <= width; x += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
    }
    for (let y = 0; y <= height; y += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
    }
    
    // Axes
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(width/2, 0); ctx.lineTo(width/2, height); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0, height/2); ctx.lineTo(width, height/2); ctx.stroke();
    ctx.restore();
  };

  // Redraw canvas with all figures
  const redrawCanvas = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const width = canvas.width;
    const height = canvas.height;

    drawGridAndAxes(ctx, width, height);

    // Draw all figures
    figures.forEach(fig => {
      ctx.save();
      ctx.strokeStyle = fig.color;
      ctx.lineWidth = fig.lineWidth;
      ctx.fillStyle = fig.color;

      const centerX = width / 2;
      const centerY = height / 2;

      switch (fig.type) {
        case 'point':
          ctx.beginPath();
          ctx.arc(centerX + fig.params.x, centerY - fig.params.y, 3, 0, 2 * Math.PI);
          ctx.fill();
          break;

        case 'line':
          ctx.beginPath();
          ctx.moveTo(centerX + fig.params.x1, centerY - fig.params.y1);
          ctx.lineTo(centerX + fig.params.x2, centerY - fig.params.y2);
          ctx.stroke();
          break;

        case 'circle':
          ctx.beginPath();
          ctx.arc(centerX + fig.params.centerX, centerY - fig.params.centerY, fig.params.radius, 0, 2 * Math.PI);
          ctx.stroke();
          break;

        case 'rectangle':
          ctx.beginPath();
          ctx.rect(
            centerX + fig.params.centerX - fig.params.width/2,
            centerY - fig.params.centerY - fig.params.height/2,
            fig.params.width,
            fig.params.height
          );
          ctx.stroke();
          break;

        case 'triangle':
          ctx.beginPath();
          ctx.moveTo(centerX + fig.params.x1, centerY - fig.params.y1);
          ctx.lineTo(centerX + fig.params.x2, centerY - fig.params.y2);
          ctx.lineTo(centerX + fig.params.x3, centerY - fig.params.y3);
          ctx.closePath();
          ctx.stroke();
          break;

        case 'ellipse':
          ctx.beginPath();
          ctx.ellipse(
            centerX + fig.params.centerX,
            centerY - fig.params.centerY,
            fig.params.radiusX,
            fig.params.radiusY,
            0, 0, 2 * Math.PI
          );
          ctx.stroke();
          break;
      }
      ctx.restore();
    });
  };

  // Initialize canvas and redraw on mount
  useEffect(() => {
    redrawCanvas();
  }, [figures]);

  // Mouse coordinate display
  const handleMouseMove = (e) => {
    const rect = canvasRef.current.getBoundingClientRect();
    const x = Math.round(e.clientX - rect.left - canvasRef.current.width/2);
    const y = Math.round(canvasRef.current.height/2 - (e.clientY - rect.top));
    setMouseCoords({ x, y });
  };

  const handleMouseLeave = () => setMouseCoords({ x: '--', y: '--' });

  // Handle drawing
  const handleDraw = () => {
    if (selectedShape === 'select') {
      alert('Please select a shape first');
      return;
    }

    // Validate all parameters are filled
    const def = shapeDefinitions[selectedShape];
    const allParamsFilled = def.params.every(param => 
      shapeParams[param.name] !== undefined && shapeParams[param.name] !== ''
    );

    if (!allParamsFilled) {
      alert('Please fill all parameters');
      return;
    }

    // Add new figure
    const newFigure = {
      type: selectedShape,
      params: { ...shapeParams },
      color,
      lineWidth
    };

    setFigures(prev => [...prev, newFigure]);
    setRedoStack([]); // Clear redo stack when new figure is drawn
  };

  // Handle undo
  const handleUndo = () => {
    if (figures.length > 0) {
      const lastFigure = figures[figures.length - 1];
      setFigures(prev => prev.slice(0, -1));
      setRedoStack(prev => [...prev, lastFigure]);
    }
  };

  // Handle redo
  const handleRedo = () => {
    if (redoStack.length > 0) {
      const figureToRedo = redoStack[redoStack.length - 1];
      setFigures(prev => [...prev, figureToRedo]);
      setRedoStack(prev => prev.slice(0, -1));
    }
  };

  // Handle clear
  const handleClear = () => {
    setFigures([]);
    setRedoStack([]);
  };

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.ctrlKey) {
        switch (e.key.toLowerCase()) {
          case 'd':
            e.preventDefault();
            handleDraw();
            break;
          case 'z':
            e.preventDefault();
            handleUndo();
            break;
          case 'y':
            e.preventDefault();
            handleRedo();
            break;
          case 'c':
            e.preventDefault();
            handleClear();
            break;
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedShape, shapeParams, color, lineWidth]);

  return (
    <Box sx={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>Draze - Where Shapes Take Form</Typography>
          <Button color="inherit" onClick={() => setModalOpen(true)}>User Manual</Button>
          <IconButton color="inherit" onClick={() => setDrawerOpen(true)}><BrushIcon /></IconButton>
          <IconButton color="inherit" onClick={handleUndo}><UndoIcon /></IconButton>
          <IconButton color="inherit" onClick={handleRedo}><RedoIcon /></IconButton>
          <IconButton color="inherit" onClick={handleClear}><DeleteIcon /></IconButton>
        </Toolbar>
      </AppBar>

      <Box sx={{ display: 'flex', flexGrow: 1, minHeight: 0 }}>
        <Drawer
          variant="persistent"
          open={drawerOpen}
          sx={{ width: 300, flexShrink: 0 }}
          PaperProps={{ sx: { width: 300, boxSizing: 'border-box', padding: 2 } }}
        >
          <Typography variant="subtitle1" sx={{ mt: 2, mb: 1 }}>TOOLS</Typography>
          <select
            value={selectedShape}
            onChange={e => { setSelectedShape(e.target.value); setShapeParams({}); }}
            style={{ width: '100%', marginBottom: 12, padding: 8 }}
          >
            {Object.entries(shapeDefinitions).map(([key, def]) => (
              <option key={key} value={key}>{def.text}</option>
            ))}
          </select>

          {shapeDefinitions[selectedShape].params.map(param => (
            <Box key={param.name} sx={{ mb: 1 }}>
              <Input
                type="number"
                placeholder={param.label}
                value={shapeParams[param.name] || ''}
                onChange={e => setShapeParams({ ...shapeParams, [param.name]: e.target.value })}
                sx={{ width: '100%' }}
              />
            </Box>
          ))}

          <Divider sx={{ my: 2 }} />
          <Typography variant="subtitle2">INFO & PROPERTIES</Typography>
          <Box sx={{ mb: 1, mt: 1 }}>
            <span>X: {mouseCoords.x}</span> <span style={{ marginLeft: 12 }}>Y: {mouseCoords.y}</span>
          </Box>
          <Box sx={{ mb: 2 }}>
            <label>Choose Colour:</label>
            <Input type="color" value={color} onChange={e => setColor(e.target.value)} sx={{ width: '100%' }} />
          </Box>
          <Box sx={{ mb: 2 }}>
            <label>Choose Width: <span>{lineWidth}</span></label>
            <Slider min={1} max={10} step={0.5} value={lineWidth} onChange={(_, v) => setLineWidth(v)} />
          </Box>
          <Button variant="contained" onClick={handleDraw} sx={{ mt: 2 }}>Draw (Ctrl+D)</Button>
        </Drawer>

        <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'row', minHeight: 0 }}>
          <Box sx={{ flex: 3, display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: '#f9fafb' }}>
            <canvas
              ref={canvasRef}
              width={600}
              height={450}
              style={{ border: '1px solid #e5e7eb', background: '#fff', borderRadius: 6 }}
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
            />
          </Box>
          <Box sx={{ width: 350, padding: 2, background: '#f9fafb', borderLeft: '1px solid #d1d5db', height: '100%' }}>
            <Typography variant="subtitle2" sx={{ mb: 1 }}>Figure Data (JSON)</Typography>
            <textarea
              value={figures.length ? JSON.stringify(figures, null, 2) : ''}
              readOnly
              style={{ width: '100%', height: '90%', fontFamily: 'monospace', fontSize: 14, background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: 6 }}
              placeholder="Drawn figures data will appear here..."
            />
          </Box>
        </Box>
      </Box>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <Box sx={{ 
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          width: 400,
          bgcolor: 'background.paper',
          boxShadow: 24,
          p: 4,
          borderRadius: 2
        }}>
          <Typography variant="h6" component="h2" sx={{ mb: 2 }}>User Manual</Typography>
          <Typography variant="body2" sx={{ mb: 2 }}>
            Welcome to Draze! This tool allows you to draw various geometric shapes on a canvas.
          </Typography>
          <Typography variant="subtitle2" sx={{ mb: 1 }}>Keyboard Shortcuts:</Typography>
          <Typography variant="body2" component="div" sx={{ mb: 2 }}>
            • Ctrl+D: Draw the selected figure<br />
            • Ctrl+Z: Undo the last action<br />
            • Ctrl+Y: Redo the last undone action<br />
            • Ctrl+C: Clear all figures
          </Typography>
          <Typography variant="subtitle2" sx={{ mb: 1 }}>Basic Usage:</Typography>
          <Typography variant="body2" component="div" sx={{ mb: 2 }}>
            1. Select a figure type from the dropdown<br />
            2. Enter the required dimensions<br />
            3. Choose a color and line thickness<br />
            4. Click Draw or press Ctrl+D<br />
            5. View JSON in the Figure Data panel<br />
            6. Use Undo, Redo, and Clear as needed
          </Typography>
          <Button onClick={() => setModalOpen(false)} variant="contained" sx={{ mt: 2 }}>Close</Button>
        </Box>
      </Modal>
    </Box>
  );
}

export default App;
